        #billing-new .sponsored-payment .sponsor-paying-field .switch-container .switch {
            display: inline-block;
            height: 16px;
            position: relative;
            width: 29px
        }
        
        #billing-new .sponsored-payment .sponsor-paying-field .switch-container .switch .slider {
            cursor: pointer;
            position: absolute;
            top: 0;
            left: 1px;
            bottom: 0;
            right: 0;
            background-color: #ebedf0;
            border-radius: 34px;
            transition: 0.4s
        }
        
        #billing-new .sponsored-payment .sponsor-paying-field .switch-container .switch .slider:before,
        .billing-address-panel .sponsor-paying-field .switch .slider:before {
            content: "";
            position: absolute;
            height: 14px;
            width: 14px;
            background-color: #fff;
            border-radius: 50%;
            transition: 0.4s;
            bottom: 1px
        }
        
        #billing-new .sponsored-payment .sponsor-paying-field .switch-container .switch input:checked+.slider:before,
        .billing-address-panel .sponsor-paying-field .switch input:checked+.slider:before {
            background-color: #e51470;
            transform: translateX(14px)
