        .desktop-footer {
            background-color: #082135;
            color: #b1c0cf;
            font-size: 12px;
            padding: 35px 75px 15px;
            position: relative;
            width: 100%;
            z-index: 2
        }
        
        @media only screen and (max-width:768px) {
            .desktop-footer {
                display: none
            }
        }
        
        .desktop-footer a {
            color: #b1c0cf
        }
        
        .desktop-footer .desktop-logo {
            margin-bottom: 25px;
            text-align: center
        }
        
        .desktop-footer .desktop-logo img {
            height: 70px
        }
        
        .desktop-top-footer {
            display: flex;
            justify-content: space-between
        }
        
        .desktop-top-footer .desktop-links {
            font-size: 14px
        }
        
        .desktop-top-footer .desktop-links a {
            display: block
        }
        
        .desktop-top-footer .desktop-links:hover {
            color: #fff
        }
        
        .desktop-top-footer .desktop-links .desktop-edx-logo {
            padding-top: 10px;
            height: 62px;
            width: 105px
        }
        
        .desktop-top-footer .desktop-social {
            margin: auto
        }
        
        .desktop-top-footer .desktop-social .desktop-social-branding {
            display: flex;
            flex-direction: row;
            justify-content: center;
            margin-bottom: 25px
        }
        
        .desktop-top-footer .desktop-social .desktop-social-branding a {
            margin: 3px
        }
        
        .desktop-top-footer .desktop-contact .footer-address {
            margin-bottom: 10px
        }
        
        .desktop-top-footer .desktop-contact .footer-address span {
            display: block
        }
        
        .desktop-top-footer .desktop-contact .desktop-phone-numbers {
            display: flex;
            flex-direction: column
        }
        
        .desktop-top-footer .desktop-contact .desktop-phone-numbers .row label {
            display: inline-block;
            font-weight: bold;
            margin-bottom: unset;
            width: 60px;
            line-height: 1.8
        }
        
        .desktop-subfooter {
            margin-top: -20px
        }
        
        .legals {
            text-align: center
        }
        
        .legals hr {
            margin-bottom: 25px
        }
        
        @media only screen and (min-width:769px) {}
        
        .floating-field {
            position: relative;
            padding-bottom: 2px
        }
        
        .floating-field *:disabled {
            cursor: not-allowed
        }
        
        .floating-field input {
            width: 100%;
            outline: none
        }
        
        .floating-field select {
            -webkit-appearance: none;
            -moz-appearance: none
        }
        
        .floating-field label {
            font-weight: 100;
            position: absolute;
            transition: all 200ms
        }
        
        .new-registration.floating-field {
            margin: 10px 0;
            width: 100%
        }
        
        .new-registration.floating-field input {
            background: #f6f6f6;
            border: 1px solid #eaeef3;
            border-radius: 5px;
            height: 60px;
            padding: 15px;
            padding-bottom: 0;
            font-size: 16px
        }
        
        .new-registration.floating-field label {
            top: 20px;
            left: 15px
        }
        
        .new-registration.floating-field select {
            color: #000;
            width: 100%;
            border: 1px solid #eaeef3;
            border-radius: 5px;
            height: 60px;
            background: url(data:image/svg+xml;base64,)no-repeat right #f6f6f6;
            -webkit-appearance: none;
            -moz-appearance: none;
            appearance: none;
            background-position-x: right;
            cursor: pointer;
            padding: 15px;
            padding-bottom: 0
        }
        
        body {
            color: #212529
        }
        
        .razmatazz-button {
            align-items: center;
            background-color: #e51470;
            border-radius: 28px;
            color: #ffffff;
            display: inline-flex;
            height: 46px;
            justify-content: center;
            text-align: center;
            width: 168px;
            border: 0
        }
        
        .razmatazz-button:focus {
            outline: #388dd3 auto 4px!important
        }
        
        .razmatazz-button:active {
            background-color: #bb0063
        }
        
        .razmatazz-button:focus {
            color: #ffffff;
            outline-offset: 3px;
            text-decoration: none
        }
        
        .razmatazz-button:hover {
            background-color: #d10067;
            color: #ffffff
        }
        
        .razmatazz-button:disabled {
            background-color: #eaeef3;
            color: #9a9ea3
        }
        
        * {
            font-family: "NotoSans", sans-serif
        }
        
        a:hover,
        a :focus {
            color: inherit;
            text-decoration: none
        }
        
        b {
            font-weight: bold
        }
        
        body .row {
            margin: 0
        }
        
        body #content {
            padding: 0
        }
        
        body .alert {
            margin: 56px 0 0 0;
            text-align: left
        }
        
        body .alert-success {
            color: #155724;
            background-color: #d4edda;
            border-color: #c3e6cb
        }
        
        @media only screen and (min-width:1250px) {
            body #content,
            body .alert {
                margin-top: 104px
            }
        }
        
        body .alert+#content {
            margin-top: 0
        }
        
        input:focus,
        textarea:focus {
            outline-color: white
        }
        
        select:focus:focus {
            outline: #388dd3 auto 4px!important
        }
        
        .spacer {
            flex-grow: 1
        }
        
        body {
            font-size: 14px
        }
        
        .row {
            display: initial;
            flex-wrap: initial
        }
        
        #nav-bar>.line {
            box-sizing: border-box;
            height: 70%;
            width: 1px;
            border: 0.5px solid #b1c0cf
        }
        
        @media only screen and (min-width:768px) {
            #nav-bar>.line {
                z-index: 200
            }
        }
        
        #header-desktop {
            position: fixed;
            top: 0;
            z-index: 100;
            width: 100%;
            display: none
        }
        
        @media only screen and (min-width:1250px) {
            #header-desktop {
                display: block
            }
        }
        
        #header-desktop a {
            text-decoration: none
        }
        
        #header-desktop .top-bar {
            display: flex;
            background-color: #eff2f5;
            height: 40px
        }
        
        #header-desktop .top-bar a {
            color: #082135;
            font-size: 12px
        }
        
        #header-desktop .top-bar .tabs {
            display: flex
        }
        
        #header-desktop .top-bar .tabs .tab {
            line-height: 40px;
            width: 160px;
            text-align: center;
            vertical-align: middle;
            cursor: pointer
        }
        
        #header-desktop .top-bar .tabs .tab.active {
            background-color: #082135;
            color: #eff2f5
        }
        
        #header-desktop .top-bar .user-options {
            margin-left: auto;
            padding-right: 20px;
            line-height: 40px;
            text-align: center;
            vertical-align: middle
        }
        
        #header-desktop .top-bar .currency-select {
            align-items: center;
            display: flex;
            padding-right: 20px
        }
        
        #header-desktop #nav-bar {
            display: flex;
            justify-content: space-between;
            align-items: center;
            width: 100%;
            height: 64px;
            background-color: #082135;
            box-shadow: 0 3px 6px 0 rgba(0, 0, 0, 0.16), 0 3px 6px 0 rgba(0, 0, 0, 0.23)
        }
        
        #header-desktop #nav-bar a {
            color: #eff2f5
        }
        
        #header-desktop #nav-bar .logo {
            cursor: pointer;
            background-color: #082135;
            line-height: 64px;
            height: 64px;
            padding: 0px 3px 0px 10px;
            margin-right: 20px;
            z-index: 200
        }
        
        #header-desktop #nav-bar .logo img {
            height: 100%
        }
        
        @media only screen and (min-width:1250px) {
            #header-desktop #nav-bar .logo {
                margin-left: 10px
            }
        }
        
        #header-desktop #nav-bar .navs {
            display: flex;
            flex-wrap: nowrap;
            justify-content: space-evenly;
            width: 100%;
            line-height: 64px;
            min-width: 450px;
            margin-left: auto;
            margin-right: auto
        }
        
        #header-desktop #nav-bar .navs a {
            font-size: 16px;
            padding-left: 10px;
            padding-right: 10px;
            margin: 0px 5px;
            white-space: nowrap
        }
        
        #header-desktop #nav-bar .navs a:not(.img):hover {
            background-color: #06101a
        }
        
        #header-desktop #nav-bar .navs a:active {
            background-color: black
        }
        
        #header-desktop #nav-bar .cart {
            display: flex;
            align-items: center;
            margin-left: auto;
            padding-left: 20px;
            padding-right: 20px
        }
        
        #header-desktop #nav-bar .cart a {
            color: white
        }
        
        #header-desktop #nav-bar .cart .cart-count {
            background-color: white;
            border: solid 1px #082135;
            border-radius: 28px;
            position: relative;
            top: -16px;
            right: 16px;
            height: 23px;
            width: 23px;
            text-align: center;
            color: #082135
        }
        
        #header-desktop #nav-bar .cart .razmatazz-button {
            text-transform: capitalize
        }
        
