            .xpert-chatbot-button:hover,
            .xpert-chatbot-button__animated_graduate__launch-button:hover {
                box-shadow: inset 0 0 0 .2143rem #8f8f8f
            }
            
            @keyframes blink-animation {
                0% {
                    transform-origin: center;
                    transform: translateZ(0)
                }
                50% {
                    transform-origin: center;
                    transform: translateY(0) translate3d(.5rem, 0, 0)
                }
                75% {
                    transform-origin: center;
                    transform: scaleY(.05) translateY(9.375rem) translate3d(.25rem, 0, 0)
                }
                to {
                    transform-origin: center;
                    transform: translateY(0) translateZ(0)
                }
            }
            
            @keyframes eye-blink-animation {
                0% {
                    transform-origin: center;
                    transform: translateY(0)
                }
                50% {
                    transform-origin: center;
                    transform: translateY(0)
                }
                75% {
                    transform-origin: center;
                    transform: scaleY(.05) translateY(9.375rem)
                }
                to {
                    transform-origin: center;
                    transform: translateY(0)
                }
            }
            
            @keyframes mouth-animation {
                0% {
                    transform-origin: center;
                    transform: translateZ(0)
                }
                50% {
                    transform-origin: center;
                    transform: translate3d(.125rem, 0, 0)
                }
                to {
                    transform-origin: center;
                    transform: translateZ(0)
                }
            }
            
            @keyframes bump {
                20% {
                    transform: scale(.5);
                    opacity: .27
                }
                50% {
                    transform: scale(.7);
                    opacity: .5
                }
                to {
                    transform: scale(1);
                    opacity: 1
                }
                10% {
                    transform: scale(1.1);
                    opacity: 1
                }
            }
            
            @media (max-width:61.9375rem) {}
            
            @keyframes spin {
                0% {
                    transform: rotate(0)
                }
